interface User {
  id: number;
  name: string;
  email?: string;
  createdAt: Date;
  role?: string;
}

type RequiredUser = Required<User>;

const user1: RequiredUser = {
  id: 1,
  name: "Alice",
  email: "alice@example.com",
  createdAt: new Date(),
  role: "admin"
};

type ReadonlyUser = Readonly<User>;

const user2: ReadonlyUser = {
  id: 2,
  name: "Bob",
  createdAt: new Date()
};

// user2.id = 3; // Error: Cannot assign to 'id' because it is a read-only property.

type UserUpdate = Partial<User>;

function updateUser(user: User, updates: UserUpdate): User {
  return { ...user, ...updates };
}

const updatedUser = updateUser(user1, { email: "newemail@example.com" });

type UserNameAndEmail = Pick<User, "name" | "email">;

const contactInfo: UserNameAndEmail = {
  name: "Alice",
  email: "alice@example.com"
};

// Omit createdAt and id

type UserWithoutMetadata = Omit<User, "id" | "createdAt">;

const partialUser: UserWithoutMetadata = {
